import{_ as e}from"./chunks/install-sdk.CtHtwMbm.js";import{_ as a,o as r,c as o,a4 as l}from"./chunks/framework.BMymQDdR.js";const k=JSON.parse('{"title":"使用 SDK 安装环境","description":"","frontmatter":{},"headers":[],"relativePath":"course/install-sdk.md","filePath":"zh/course/install-sdk.md","lastUpdated":1735987863000}'),i={name:"course/install-sdk.md"},t=l('<h1 id="使用-sdk-安装环境" tabindex="-1">使用 SDK 安装环境 <a class="header-anchor" href="#使用-sdk-安装环境" aria-label="Permalink to &quot;使用 SDK 安装环境&quot;">​</a></h1><h3 id="环境集成-sdk-下载地址" tabindex="-1">环境集成 SDK 下载地址 <a class="header-anchor" href="#环境集成-sdk-下载地址" aria-label="Permalink to &quot;环境集成 SDK 下载地址&quot;">​</a></h3><ul><li><a href="https://sourceforge.net/projects/energye/files/sdk/" target="_blank" rel="noreferrer">sourceforge</a></li><li><a href="https://pan.baidu.com/s/1XdtfMxmM5YciLWFyC90l3Q?pwd=8b3y" target="_blank" rel="noreferrer">百度网盘</a> 提取码: 8b3y</li><li><a href="https://caiyun.139.com/m/i?2jexCZksHP4od" target="_blank" rel="noreferrer">移动云盘</a> 提取码: caea</li><li><a href="http://cloud.189.cn/t/MreEzeuY7fue" target="_blank" rel="noreferrer">天翼云盘</a> 提取码: wtk0</li><li><a href="https://pan.quark.cn/s/1dc97bb4280d" target="_blank" rel="noreferrer">夸克网盘</a></li></ul><h3 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h3><p>现有 energy <a href="https://github.com/energye/energy/releases" target="_blank" rel="noreferrer">发行版本</a> 开发环境离线安装包</p><p>一搬只在发布 LibLCL 新版本才发布 SDK</p><ul><li>目录 sdk/vx.x.x : 对应的发行版本号目录</li><li>安装程序 sdk/vx.x.x/ENERGY-SDK_* : SDK 安装程序</li><li>安装程序文件名: <code>ENERGY-SDK_[VER]_[CEF]_[OS][ARCH]</code></li></ul><p><code>[VER]</code> energy 发行版本号</p><p><code>[CEF]</code> CEF 版本号</p><p><code>[OS]</code> 操作系统</p><p><code>[ARCH]</code> 系统架构</p><ul><li>示例, 例如我想使用 v2.5.1 发行版本, CEF 109 版本, Windows 32 位的</li></ul><p>对应的是 <code>ENERGY-SDK_v2.5.1_109_windows32.exe</code></p><h3 id="安装和使用" tabindex="-1">安装和使用 <a class="header-anchor" href="#安装和使用" aria-label="Permalink to &quot;安装和使用&quot;">​</a></h3><h4 id="windows-linux" tabindex="-1">Windows Linux <a class="header-anchor" href="#windows-linux" aria-label="Permalink to &quot;Windows Linux&quot;">​</a></h4><ol><li>下载</li><li>双击打开</li><li>点击安装图标按钮</li><li>选择安装目录</li></ol><h4 id="macos" tabindex="-1">MacOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;MacOS&quot;">​</a></h4><ol><li>下载</li><li>双击打开, 会自动生成<code>当前执行文件名 .app 包</code></li><li>点击安装图标按钮</li><li>选择安装目录</li></ol><p>注意: <code>MacOS 可能有程序未知、不安全、等提示，需要在系统偏好里允许其运行</code></p><h4 id="其它说明-安装目录" tabindex="-1">其它说明: 安装目录 <a class="header-anchor" href="#其它说明-安装目录" aria-label="Permalink to &quot;其它说明: 安装目录&quot;">​</a></h4><p>使用 sdk 或 cli 安装开发环境时，安装目录是一个根目录</p><ul><li>sdk 安装时选择的目录</li><li>cli 安装时默认是在当前目录. 如果想修改它, 先初始化环境配置 <code>energy env</code> 然后修改 <code>energy env -w root:E:/app</code></li></ul><p>在安装时，会在根目录生成一个固定文件夹 &quot;energy&quot; 它是实际存放安装的 CEF Framework 和其它工具的目录</p><p>例如安装目录: <code>E:/app</code> or <code>/home/xxx/app</code> &gt; 安装后 <code>E:/app/energy/xxx</code> or <code>/home/xxx/app/energy/xxx</code></p><p>在当前系统用户目录生成 <code>.energy</code> 开发环境配置文件</p><h3 id="安装界面" tabindex="-1">安装界面 <a class="header-anchor" href="#安装界面" aria-label="Permalink to &quot;安装界面&quot;">​</a></h3><p><img src="'+e+'" alt="install-SDK"></p>',27),d=[t];function c(n,s,h,p,u,_){return r(),o("div",null,d)}const m=a(i,[["render",c]]);export{k as __pageData,m as default};
